"use strict";parserFactory.register("asianfanfics.com",()=>new AsianfanficsParser);class AsianfanficsParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.querySelector("aside ul");return util.hyperlinksToChapterList(e)}findContent(t){return t.querySelector("div#user-submitted-body")}extractTitleImpl(t){return t.querySelector("h1#story-title")}findChapterTitle(t){return t.querySelector("h1#chapter-title")}findCoverImageUrl(t){return util.getFirstImgSrc(t,"div#bodyText")}async fetchChapter(t){let e=(await HttpClient.fetchHtml(t)).responseXML,r=this.findPostApi(e);if(!util.isNullOrEmpty(r)){let t="https://www.asianfanfics.com"+r,i=(await HttpClient.fetchJson(t)).json;i.post||(i=(await HttpClient.fetchJson(t+"?v=1")).json),this.addJsonToContent(i,e)}return e}findPostApi(t){return[...t.querySelectorAll("script")].filter(t=>t.textContent.startsWith("var postApi")).map(t=>t.textContent.split('"')[1])[0]}addJsonToContent(t,e){let r=this.findContent(e),i=util.sanitize("<div>"+t.post+"</div>").querySelector("div");r.append(i)}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("#story-description, #story-foreword")]}}